import React, { useState } from 'react'
import { CopyToClipboard } from 'react-copy-to-clipboard';
import CIcon from '@coreui/icons-react';
import { cilCopy } from '@coreui/icons';

const CopyPaymentLink = (props) => {
    const [copied, setCopied] = useState(false);

    const handleCopy = () => {
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <div>
            <CopyToClipboard text={props?.paymentlink} onCopy={handleCopy}>
                <CIcon icon={cilCopy} style={{ color: '#008c6e', width: '24px', height: '24px' }} />
            </CopyToClipboard>
            {copied && <div style={{ color: 'green' }}>Copied!</div>}
        </div>
    );
}

export default CopyPaymentLink;
